// 1. Initialize an empty string to accumulate the clean HTML article rows
let newsletterHtml = '';

// 2. Loop through every single row object returned by your Notion node
for (const item of $input.all()) {
  try {
    // Directly target the flat property keys revealed in your n8n input mapping
    const title = item.json.property_title || 'Untitled Article';
    const summary = item.json.property_news_summary || 'No summary available.';
    const link = item.json.property_url || '#';

    // 3. Stack the HTML layout block for this specific news piece
    newsletterHtml += `
    <div style="margin-bottom: 25px; padding-bottom: 20px; border-bottom: 1px dashed #e2e8f0;">
      <h3 style="margin: 0 0 10px 0; color: #1a202c; font-size: 18px; font-weight: 600; line-height: 1.4;">
        🔔 ${title}
      </h3>
      <div style="color: #4a5568; font-size: 14px; white-space: pre-line; margin-bottom: 12px; line-height: 1.6;">
        ${summary}
      </div>
      <a href="${link}" target="_blank" style="color: #4f46e5; font-size: 13px; text-decoration: none; font-weight: 700; display: inline-block;">
        Read Original Article &rarr;
      </a>
    </div>
    `;
  } catch (error) {
    // Skip any broken item loops gracefully to avoid breaking the entire digest summary
    continue;
  }
}

// 4. Verification fallback if the database filter returned zero results
if (!newsletterHtml) {
  newsletterHtml = '<p style="color: #718096; font-style: italic; text-align: center; padding: 20px;">No new industry developments logged over the last 24 hours.</p>';
}

// 5. Package and return the payload cleanly to the email dispatcher
return [{
  json: {
    html: newsletterHtml
  }
}];

// Loop over input items from the HTTP Request node using n8n's modern syntax
for (const item of $input.all()) {
    // Grab the raw HTML data safely
    const rawHtml = item.json.data || "";

    if (rawHtml) {
        // Step 1: Remove all <script> and <style> blocks along with their contents
        let text = rawHtml.replace(/<(script|style)[^>]*>[\s\S]*?<\/\1>/gi, '');

        // Step 2: Strip out all remaining HTML tags (like <p>, <a>, <div>)
        text = text.replace(/<[^>]+>/g, ' ');

        // Step 3: Clean up messy whitespace, tabs, and duplicate empty lines
        const cleanText = text.replace(/\s+/g, ' ').trim();

        // Step 4: Create a new field to hold our perfectly clean text
        item.json.clean_article_text = cleanText;
    } else {
        item.json.clean_article_text = "No content to parse.";
    }
}

// Output the modified data to the next node
return $input.all();

