const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(now.getDate() - 1);

return $input.all().filter(item => {

  const created = new Date(item.json.property_created_time.start);

  return (
    created >= yesterday &&
    created < now 
  );

});
